    <div>
      <h1 class="text-2xl font-black text-slate-900 dark:text-slate-100 tracking-tight uppercase leading-none">Mis Cursos (Docente)</h1>
      <p class="text-slate-500 dark:text-slate-400 text-xs mt-2">Administra tus cursos asignados con búsqueda, orden por fecha y paginación consistente.</p>
    </div>
    <div class="flex flex-col sm:flex-row gap-3 w-full lg:w-auto">
      <label class="flex items-center gap-2 border border-slate-200 dark:border-slate-700 px-3 py-2 bg-slate-50 dark:bg-slate-800 w-full sm:w-72">
        <span class="material-symbols-outlined text-sm text-slate-400">search</span>
        <input [(ngModel)]="searchTerm" (ngModelChange)="onSearchChange()" type="text" placeholder="Buscar curso, docente o fecha" class="w-full bg-transparent outline-none text-sm">
      </label>
      <button (click)="toggleDateSort()" class="px-4 py-2 border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-xs font-bold uppercase tracking-widest flex items-center gap-2">
